.darma-loader-cssloaders-github-01 {
  display: inline-block;
  width: 94px;
  height: 10px;
  border-radius: 999px;
  background: linear-gradient(90deg, var(--loader-color, #22c55e) 25%, var(--loader-secondary-color, #bbf7d0) 25%, var(--loader-secondary-color, #bbf7d0) 50%, var(--loader-color, #22c55e) 50%, var(--loader-color, #22c55e) 75%, var(--loader-secondary-color, #bbf7d0) 75%);
  background-size: 32px 100%; animation: darma-loader-cssloaders-github-01-progressStripe 0.97s linear infinite;
}
